188→function tildeResolverPlugin(): PluginOption {
189→  return {
190→    name: 'storybook:tilde-resolver',
191→    enforce: 'pre',
192→    resolveId(source, importer) {
193→      if (!source.startsWith('~/') || !importer) return;
194→      if (importer.includes('node_modules')) return;
195→
196→      const mock = TILDE_MOCKS[source];
197→      if (mock) return mock;
198→
199→      return path.resolve(SRC_DIR, source.slice(2));
200→    },
201→  };
202→}
